local pS = require(script.Parent.Type)
local pR = require(script.Parent.Symbol)
local function p1()
	return nil
end
local qP = {}
qP.UseParentKey = pR.named("UseParentKey")
function qP.iterateElements(qQ)
	local qR = pS.of(qQ)
	if qR == pS.Element then
		local qS = false
		return function()
			if qS then
				return nil
			else
				qS = true
				return qP.UseParentKey, qQ
			end
		end
	end
	local qT = typeof(qQ)
	if qQ == nil or qT == "boolean" then
		return p1
	end
	if qT == "table" then
		return pairs(qQ)
	end
	error("Invalid elements")
end
function qP.getElementByKey(qU, qV)
	if qU == nil or typeof(qU) == "boolean" then
		return nil
	end
	if pS.of(qU) == pS.Element then
		if qV == qP.UseParentKey then
			return qU
		end
		return nil
	end
	if typeof(qU) == "table" then
		return qU[qV]
	end
	error("Invalid elements")
end
return qP
